  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);
```

---

### 5. 🟠 Hardcoded Port
Using `process.env.PORT` is a security and portability best practice — hardcoded ports can conflict or expose the app unexpectedly:

```js
