```js
const express = require('express');
const helmet = require('helmet');        // Security headers
const rateLimit = require('express-rate-limit'); // Rate limiting

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security Middleware ---

// Sets Content-Security-Policy, X-Frame-Options, X-Content-Type-Options, etc.
app.use(helmet());

// Parse JSON bodies with a size limit to prevent payload bloat attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// Rate limiting: max 100 requests per 15 minutes per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---

app.get('/health', (req, res) => {
  // Avoid leaking server internals; omit timestamp or gate it behind auth
  res.json({ status: 'ok' });
});

app.get('/users', (req, res, next) => {
  try {
    // Validate and sanitize query params if filtering is added
    const { page = 1, limit = 20 } = req.query;
    const parsedPage = parseInt(page, 10);
    const parsedLimit = parseInt(limit, 10);

    if (isNaN(parsedPage) || parsedPage < 1 || isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 100) {
      return res.status(400).json({ error: 'Invalid pagination parameters.' });
    }

    // In a real app, query DB here with parameterized queries (never string interpolation)
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (err) {
    next(err); // Forward to global error handler
  }
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found.' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to recognize it as an error handler
app.use((err, req, res, next) => { // eslint-disable-line no-unused-vars
  // Log the full error internally (use a real logger like winston/pino in production)
  console.error(`[ERROR] ${req.method} ${req.url}:`, err);

  // Never expose internal stack traces to clients
  const statusCode = err.status || err.statusCode || 500;
  res.status(statusCode).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An internal server error occurred.'
      : err.message,
  });
});

// --- Start Server ---
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app;
```

